"use client";

import React, { useState, FormEvent, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAppDispatch, useAppSelector } from "@/redux/hooks";
import { login } from "@/redux/slices/auth/authSlice";
import { motion } from "framer-motion";
import Link from "next/link";
import { isAdminRole } from "@/utils/authRole";

const Login: React.FC = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const dispatch = useAppDispatch();
  const { loading, error, success, user } = useAppSelector((state) => state.auth);
  const router = useRouter();

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    await dispatch(login({ email, password }));
  };

  useEffect(() => {
    // Redirect after successful login
    if (user && success && !loading) {
      // Small delay to ensure state is fully updated
      const timer = setTimeout(() => {
        if (isAdminRole(user.role)) {
          router.replace("/admin/products");
        } else {
          router.replace("/");
        }
      }, 100);
      
      return () => clearTimeout(timer);
    }
  }, [user, success, loading, router]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-900 to-black overflow-hidden relative">
      {/* Animated gradient circle background */}
      <div className="absolute bottom-0 right-0 w-96 h-96 rounded-full bg-gradient-to-tl from-purple-500 via-pink-500 to-orange-400 opacity-20 blur-3xl animate-pulse" />
      <div className="absolute -bottom-32 -right-32 w-80 h-80 rounded-full bg-gradient-to-br from-blue-500 to-cyan-500 opacity-15 blur-2xl animate-pulse" />

      <div className="relative z-10 min-h-screen flex items-center justify-center px-4 lg:px-8">
        <div className="w-full max-w-5xl grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-12">
          {/* Left Column - Form */}
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6 }}
            className="flex flex-col justify-center"
          >
            <h1 className="text-5xl lg:text-6xl font-bold text-white mb-12">Sign In.</h1>

            <form className="space-y-6" onSubmit={handleSubmit}>
              {/* Email Field */}
              <div>
                <input
                  id="email"
                  type="email"
                  required
                  className="w-full px-4 py-3 bg-transparent border border-slate-600 rounded-lg focus:outline-none focus:border-purple-500 focus:ring-1 focus:ring-purple-500 text-white placeholder-slate-400 transition-all"
                  placeholder="Username or email*"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                />
              </div>

              {/* Password Field */}
              <div>
                <input
                  id="password"
                  type="password"
                  required
                  className="w-full px-4 py-3 bg-transparent border border-slate-600 rounded-lg focus:outline-none focus:border-purple-500 focus:ring-1 focus:ring-purple-500 text-white placeholder-slate-400 transition-all"
                  placeholder="Enter your password*"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
              </div>

              {/* Remember & Forgot */}
              <div className="flex items-center justify-between">
                <label className="flex items-center space-x-2 cursor-pointer">
                  <input
                    type="checkbox"
                    className="w-4 h-4 bg-transparent border border-slate-500 rounded focus:ring-purple-500 cursor-pointer"
                  />
                  <span className="text-sm text-slate-300">Remember this device</span>
                </label>
                <Link
                  href="/forgot-password"
                  className="text-sm text-slate-300 hover:text-white transition-colors"
                >
                  Forgot Password?
                </Link>
              </div>

              {/* Error Message */}
              {error && (
                <div className="p-3 bg-red-500/20 border border-red-500/50 rounded-lg">
                  <p className="text-sm text-red-300">{error}</p>
                </div>
              )}

              {/* Success Message */}
              {success && (
                <div className="p-3 bg-green-500/20 border border-green-500/50 rounded-lg">
                  <p className="text-sm text-green-300">{success}</p>
                </div>
              )}

              {/* Login Button */}
              <motion.button
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                type="submit"
                disabled={loading}
                className="w-full py-3 px-4 rounded-lg bg-white text-slate-900 font-semibold shadow-lg hover:shadow-xl hover:bg-slate-100 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              >
                {loading ? (
                  <>
                    <div className="w-5 h-5 border-2 border-slate-900 border-t-transparent rounded-full animate-spin" />
                    Signing in...
                  </>
                ) : (
                  "Login"
                )}
              </motion.button>
            </form>

            {/* Signup Link */}
            <p className="mt-8 text-sm text-slate-400">
              Don&apos;t have an account?{" "}
              <Link
                href="/register"
                className="text-white hover:text-purple-400 transition-colors font-semibold"
              >
                Create an account
              </Link>
            </p>
          </motion.div>

          {/* Right Column - Social Login */}
          <motion.div
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.1 }}
            className="flex flex-col justify-center"
          >
            <div className="space-y-4">
              <p className="text-slate-300 text-center mb-6">Sign in with your social account</p>

              {/* Google Login */}
              <button className="w-full px-4 py-3 border border-slate-600 rounded-lg text-white hover:border-purple-500 hover:text-purple-400 transition-all flex items-center justify-center gap-2">
                <svg className="w-5 h-5" viewBox="0 0 24 24">
                  <path
                    fill="currentColor"
                    d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                  />
                  <path
                    fill="currentColor"
                    d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                  />
                  <path
                    fill="currentColor"
                    d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                  />
                </svg>
                Sign in with Google
              </button>

              {/* Twitter Login */}
              <button className="w-full px-4 py-3 border border-slate-600 rounded-lg text-white hover:border-purple-500 hover:text-purple-400 transition-all flex items-center justify-center gap-2">
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M23.953 4.57a10 10 0 002.856-9.835-9.993 9.993 0 03-14.46 3.55 1.001 1.001 0 10-.066-1.457 7.456 7.456 0 00-10.823 1.72c-2.096 2.466-2.033 6.16.188 8.133A1.001 1.001 0 003 15.5v-1.5c0-5.523 4.477-10 10-10s10 4.477 10 10-4.477 10-10 10H3a1 1 0 100 2h10c6.627 0 12-5.373 12-12 0-.563-.047-1.12-.135-1.67.06-.264.06-.534 0-.801z" />
                </svg>
                Sign in with Twitter
              </button>

              {/* Facebook Login */}
              <button className="w-full px-4 py-3 border border-slate-600 rounded-lg text-white hover:border-purple-500 hover:text-purple-400 transition-all flex items-center justify-center gap-2">
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                  <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.47h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.47h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
                </svg>
                Sign in with Facebook
              </button>
            </div>

            {/* Terms */}
            <p className="mt-8 text-xs text-slate-500 text-center">
              By signing in, you agree to our{" "}
              <Link href="/terms" className="text-slate-300 hover:text-slate-200 underline">
                Terms of Service
              </Link>
              {" "}and{" "}
              <Link href="/privacy" className="text-slate-300 hover:text-slate-200 underline">
                Privacy Policy
              </Link>
            </p>
          </motion.div>
        </div>
      </div>
    </div>
  );
};

export default Login;
